local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

local function parse_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return nil, "Empty request body"
    end

    local ok, parsed = pcall(cjson.decode, body)
    if not ok then
        return nil, "Invalid JSON body: " .. tostring(parsed)
    end

    return parsed, nil
end

local function connect_redis()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. tostring(err)
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Failed to authenticate with Redis: " .. tostring(err)
        end
    end

    return red, nil
end

local function close_redis(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

local function validate_command(cmd)
    if not cmd or type(cmd) ~= "string" or cmd == "" then
        return false, "Command is required and must be a non-empty string"
    end

    local lower_cmd = string.lower(cmd)

    if BLOCKED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is blocked for security reasons"
    end

    if not ALLOWED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is not in the allowed commands list"
    end

    return true, nil
end

local function format_redis_result(result)
    if type(result) == "table" then
        -- Check if it's a redis null bulk reply
        local formatted = {}
        for i, v in ipairs(result) do
            if v == ngx.null then
                formatted[i] = cjson.null
            elseif type(v) == "table" then
                formatted[i] = format_redis_result(v)
            else
                formatted[i] = v
            end
        end
        return formatted
    elseif result == ngx.null then
        return cjson.null
    else
        return result
    end
end

-- Convert hgetall result from flat array to key-value table
local function format_hgetall_result(result)
    if type(result) ~= "table" then
        return result
    end
    local hash = {}
    for i = 1, #result, 2 do
        if result[i] then
            hash[result[i]] = result[i + 1] == ngx.null and cjson.null or result[i + 1]
        end
    end
    return hash
end

local function execute_command(red, cmd, args)
    local lower_cmd = string.lower(cmd)

    local func = red[lower_cmd]
    if not func then
        return nil, "Redis command '" .. cmd .. "' is not supported by the client library"
    end

    local result, err
    if args and #args > 0 then
        result, err = func(red, unpack(args))
    else
        result, err = func(red)
    end

    if not result then
        return nil, "Redis command execution failed: " .. tostring(err)
    end

    -- Special formatting for certain commands
    if lower_cmd == "hgetall" then
        result = format_hgetall_result(result)
    else
        result = format_redis_result(result)
    end

    return result, nil
end

local function execute_eval(red, script, keys, argv)
    if not script or type(script) ~= "string" or script == "" then
        return nil, "Lua script is required for eval"
    end

    keys = keys or {}
    argv = argv or {}

    local num_keys = #keys

    -- Build the arguments: numkeys, keys..., argv...
    local eval_args = { script, num_keys }
    for _, k in ipairs(keys) do
        eval_args[#eval_args + 1] = k
    end
    for _, a in ipairs(argv) do
        eval_args[#eval_args + 1] = a
    end

    local result, err = red:eval(unpack(eval_args))
    if not result then
        return nil, "EVAL execution failed: " .. tostring(err)
    end

    return format_redis_result(result), nil
end

local function execute_pipeline(red, commands)
    if not commands or type(commands) ~= "table" or #commands == 0 then
        return nil, "Pipeline requires a non-empty array of commands"
    end

    red:init_pipeline(#commands)

    for i, cmd_entry in ipairs(commands) do
        local cmd = cmd_entry.command or cmd_entry.cmd
        local args = cmd_entry.args or cmd_entry.arguments or {}

        if not cmd then
            return nil, "Command #" .. i .. " is missing the 'command' field"
        end

        local valid, verr = validate_command(cmd)
        if not valid then
            return nil, "Command #" .. i .. ": " .. verr
        end

        local lower_cmd = string.lower(cmd)
        local func = red[lower_cmd]
        if not func then
            return nil, "Command #" .. i .. ": Redis command '" .. cmd .. "' is not supported"
        end

        if args and #args > 0 then
            func(red, unpack(args))
        else
            func(red)
        end
    end

    local results, err = red:commit_pipeline()
    if not results then
        return nil, "Pipeline execution failed: " .. tostring(err)
    end

    local formatted_results = {}
    for i, result in ipairs(results) do
        local entry = { index = i }
        if type(result) == "table" and result[1] == false then
            entry.error = tostring(result[2])
            entry.success = false
        else
            local cmd_entry = commands[i]
            local cmd = cmd_entry.command or cmd_entry.cmd
            local lower_cmd = string.lower(cmd)

            if lower_cmd == "hgetall" then
                entry.result = format_hgetall_result(result)
            else
                entry.result = format_redis_result(result)
            end
            entry.success = true
        end
        formatted_results[i] = entry
    end

    return formatted_results, nil
end

-- Handle GET request: simple command via query parameters
local function handle_get_request()
    local args = ngx.req.get_uri_args()
    local cmd = args.command or args.cmd
    local raw_args = args.args

    if not cmd then
        return send_json_response(ngx.HTTP_BAD_REQUEST, {
            success = false,
            error = "Missing 'command' query parameter"
        })
    end

    local valid, verr = validate_command(cmd)
    if not valid then
        return send_json_response(ngx.HTTP_FORBIDDEN, {
            success = false,
            error = verr
        })
    end

    local command_args = {}
    if raw_args then
        if type(raw_args) == "table" then
            command_args = raw_args
        else
            -- Split comma-separated arguments
            for arg in string.gmatch(raw_args, "[^,]+") do
                command_args[#command_args + 1] = arg
            end
        end
    end

    -- Also support positional args like arg1, arg2, arg3...
    local i = 1
    while true do
        local arg_val = args["arg" .. i]
        if arg_val == nil then
            break
        end
        command_args[#command_args + 1] = arg_val
        i = i + 1
    end

    local red, err = connect_redis()
    if not red then
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            success = false,
            error = err
        })
    end

    local result, exec_err = execute_command(red, cmd, command_args)
    close_redis(red)

    if exec_err then
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            success = false,
            error = exec_err,
            command = cmd,
            args = command_args
        })
    end

    return send_json_response(ngx.HTTP_OK, {
        success = true,
        command = cmd,
        args = command_args,
        result = result
    })
end

-- Handle POST request: complex operations via JSON body
local function handle_post_request()
    local body, parse_err = parse_request_body()
    if not body then
        return send_json_response(ngx.HTTP_BAD_REQUEST, {
            success = false,
            error = parse_err
        })
    end

    local mode = body.mode or "command" -- "command", "eval", "pipeline"

    local red, err = connect_redis()
    if not red then
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            success = false,
            error = err
        })
    end

    -- Select database if specified
    if body.db and type(body.db) == "number" then
        local ok, db_err = red:select(body.db)
        if not ok then
            close_redis(red)
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = "Failed to select database: " .. tostring(db_err)
            })
        end
    end

    if mode == "eval" then
        -- Execute Lua script via EVAL
        local script = body.script
        local keys = body.keys or {}
        local argv = body.argv or body.args or {}

        local result, exec_err = execute_eval(red, script, keys, argv)
        close_redis(red)

        if exec_err then
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = exec_err,
                mode = "eval"
            })
        end

        return send_json_response(ngx.HTTP_OK, {
            success = true,
            mode = "eval",
            result = result
        })

    elseif mode == "pipeline" then
        -- Execute multiple commands in a pipeline
        local commands = body.commands
        local results, exec_err = execute_pipeline(red, commands)
        close_redis(red)

        if exec_err then
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = exec_err,
                mode = "pipeline"
            })
        end

        return send_json_response(ngx.HTTP_OK, {
            success = true,
            mode = "pipeline",
            results = results,
            count = #results
        })

    elseif mode == "command" then
        -- Execute single command
        local cmd = body.command or body.cmd
        local args = body.args or body.arguments or {}

        if not cmd then
            close_redis(red)
            return send_json_response(ngx.HTTP_BAD_REQUEST, {
                success = false,
                error = "Missing 'command' field in request body"
            })
        end

        local valid, verr = validate_command(cmd)
        if not valid then
            close_redis(red)
            return send_json_response(ngx.HTTP_FORBIDDEN, {
                success = false,
                error = verr
            })
        end

        local result, exec_err = execute_command(red, cmd, args)
        close_redis(red)

        if exec_err then
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = exec_err,
                command = cmd,
                args = args
            })
        end

        return send_json_response(ngx.HTTP_OK, {
            success = true,
            command = cmd,
            args = args,
            result = result
        })

    elseif mode == "multi" then
        -- Execute commands in a MULTI/EXEC transaction
        local commands = body.commands

        if not commands or type(commands) ~= "table" or #commands == 0 then
            close_redis(red)
            return send_json_response(ngx.HTTP_BAD_REQUEST, {
                success = false,
                error = "Transaction requires a non-empty array of commands"
            })
        end

        -- Validate all commands first
        for i, cmd_entry in ipairs(commands) do
            local cmd = cmd_entry.command or cmd_entry.cmd
            if not cmd then
                close_redis(red)
                return send_json_response(ngx.HTTP_BAD_REQUEST, {
                    success = false,
                    error = "Command #" .. i .. " is missing the 'command' field"
                })
            end
            local valid, verr = validate_command(cmd)
            if not valid then
                close_redis(red)
                return send_json_response(ngx.HTTP_FORBIDDEN, {
                    success = false,
                    error = "Command #" .. i .. ": " .. verr
                })
            end
        end

        local ok, multi_err = red:multi()
        if not ok then
            close_redis(red)
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = "Failed to start transaction: " .. tostring(multi_err)
            })
        end

        for i, cmd_entry in ipairs(commands) do
            local cmd = cmd_entry.command or cmd_entry.cmd
            local args = cmd_entry.args or cmd_entry.arguments or {}
            local lower_cmd = string.lower(cmd)
            local func = red[lower_cmd]

            if args and #args > 0 then
                func(red, unpack(args))
            else
                func(red)
            end
        end

        local results, exec_err = red:exec()
        close_redis(red)

        if not results then
            return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
                success = false,
                error = "Transaction execution failed: " .. tostring(exec_err),
                mode = "multi"
            })
        end

        local formatted_results = {}
        for i, result in ipairs(results) do
            formatted_results[i] = {
                index = i,
                command = (commands[i].command or commands[i].cmd),
                result = format_redis_result(result)
            }
        end

        return send_json_response(ngx.HTTP_OK, {
            success = true,
            mode = "multi",
            results = formatted_results,
            count = #formatted_results
        })

    else
        close_redis(red)
        return send_json_response(ngx.HTTP_BAD_REQUEST, {
            success = false,
            error = "Unknown mode: " .. tostring(mode) .. ". Supported modes: command, eval, pipeline, multi"
        })
    end
end

-- Handle listing available commands
local function handle_commands_list()
    local sorted_commands = {}
    for cmd, _ in pairs(ALLOWED_COMMANDS) do
        sorted_commands[#sorted_commands + 1] = cmd
    end
    table.sort(sorted_commands)

    return send_json_response(ngx.HTTP_OK, {
        success = true,
        allowed_commands = sorted_commands,
        count = #sorted_commands
    })
end

-- Handle health check / ping
local function handle_health()
    local red, err = connect_redis()
    if not red then
        return send_json_response(ngx.HTTP_SERVICE_UNAVAILABLE, {
            success = false,
            status = "unhealthy",
            error = err
        })
    end

    local result, ping_err = red:ping()
    close_redis(red)

    if not result then
        return send_json_response(ngx.HTTP_SERVICE_UNAVAILABLE, {
            success = false,
            status = "unhealthy",
            error = "Ping failed: " .. tostring(ping_err)
        })
    end

    return send_json_response(ngx.HTTP_OK, {
        success = true,
        status = "healthy",
        redis = {
            host = REDIS_HOST,
            port = REDIS_PORT,
            ping = result
        }
    })
end

-- Main request router
local method = ngx.req.get_method()
local uri = ngx.var.uri

-- Route: /redis/health
if uri == "/redis/health" or uri == "/health" then
    return handle_health()
end

-- Route: /redis/commands - list available commands
if uri == "/redis/commands" and method == "GET" then
    return handle_commands_list()
end

-- Route: /redis/exec or /redis
if uri == "/redis/exec" or uri == "/redis" or uri == "/redis/" then
    if method == "GET" then
        return handle_get_request()
    elseif method == "POST" then
        return handle_post_request()
    else
        return send_json_response(ngx.HTTP_NOT_ALLOWED, {
            success = false,
            error = "Method not allowed. Use GET or POST."
        })
    end
end

